<?phpnamespace App\Controller;use App\Entity\Region;use App\Entity\SysAdminOperation;use App\Form\RegionType;use App\Repository\RegionRepository;use DateTime;use DateTimeZone;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class RegionController extends AbstractController{    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/regions", name="region_index", methods={"GET"})     * @param RegionRepository $regionRepository     * @return Response     */    public function index(RegionRepository $regionRepository): Response    {        return $this->render('region/index.html.twig', [            'regions' => $regionRepository->findAll(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/regions/new", name="region_new", methods={"GET","POST"})     * @param Request $request     * @return Response     * @throws \Exception     */    public function new(Request $request): Response    {        $region = new Region();        $form = $this->createForm(RegionType::class, $region);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($region);            $entityManager->flush();            $this->addFlash('success', 'La région a été enregistrée');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Enregistrement de région')                ->setUserAffected($region->getName());            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('region_index');        }        return $this->render('region/new.html.twig', [            'region' => $region,            'form' => $form->createView(),        ]);    }    /**     * @Route("/super-admin/regions/{id}", name="region_show", methods={"GET"})     * @param Region $region     * @return Response     */    public function show(Region $region): Response    {        return $this->render('region/show.html.twig', [            'region' => $region,        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/regions/{id}/edit", name="region_edit", methods={"GET","POST"})     * @param Request $request     * @param Region $region     * @return Response     * @throws \Exception     */    public function edit(Request $request, Region $region): Response    {        $form = $this->createForm(RegionType::class, $region);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'La région a été modifié');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification de région')                ->setUserAffected($region->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('region_index');        }        return $this->render('region/edit.html.twig', [            'region' => $region,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/regions/{id}", name="region_delete", methods={"DELETE"})     * @param Request $request     * @param Region $region     * @return Response     * @throws \Exception     */    public function delete(Request $request, Region $region): Response    {        if ($this->isCsrfTokenValid('delete' . $region->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($region);            $entityManager->flush();            $this->addFlash('success', 'La région a été suprimée');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppression de région')                ->setUserAffected($region->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('region_index');        }        return $this->redirectToRoute('region_index');    }}